(function(){var Z=[{zone:"JHR01",state:"Johor",area:["Pulau Aur dan Pulau Pemanggil"]},{zone:"JHR02",state:"Johor",area:["Johor Bahru, Kota Tinggi, Mersing, Kulai"]},{zone:"JHR03",state:"Johor",area:["Kluang, Pontian"]},{zone:"JHR04",state:"Johor",area:["Batu Pahat, Muar, Segamat, Gemas Johor, Tangkak"]},{zone:"KDH01",state:"Kedah",area:["Kota Setar, Kubang Pasu, Pokok Sena (Daerah Kecil)"]},{zone:"KDH02",state:"Kedah",area:["Kuala Muda, Yan, Pendang"]},{zone:"KDH03",state:"Kedah",area:["Padang Terap, Sik"]},{zone:"KDH04",state:"Kedah",area:["Baling"]},{zone:"KDH05",state:"Kedah",area:["Bandar Baharu, Kulim"]},{zone:"KDH06",state:"Kedah",area:["Langkawi"]},{zone:"KDH07",state:"Kedah",area:["Puncak Gunung Jerai"]},{zone:"KTN01",state:"Kelantan",area:["Bachok, Kota Bharu, Machang, Pasir Mas, Pasir Puteh, Tanah Merah, Tumpat, Kuala Krai, Mukim Chiku"]},{zone:"KTN02",state:"Kelantan",area:["Gua Musang (Daerah Galas Dan Bertam), Jeli, Jajahan Kecil Lojing"]},{zone:"MLK01",state:"Melaka",area:["SELURUH NEGERI MELAKA"]},{zone:"NGS01",state:"Negeri Sembilan",area:["Tampin, Jempol"]},{zone:"NGS02",state:"Negeri Sembilan",area:["Jelebu, Kuala Pilah, Rembau"]},{zone:"NGS03",state:"Negeri Sembilan",area:["Port Dickson, Seremban"]},{zone:"PHG01",state:"Pahang",area:["Pulau Tioman"]},{zone:"PHG02",state:"Pahang",area:["Kuantan, Pekan, Muadzam Shah"]},{zone:"PHG03",state:"Pahang",area:["Jerantut, Temerloh, Maran, Bera, Chenor, Jengka"]},{zone:"PHG04",state:"Pahang",area:["Bentong, Lipis, Raub"]},{zone:"PHG05",state:"Pahang",area:["Genting Sempah, Janda Baik, Bukit Tinggi"]},{zone:"PHG06",state:"Pahang",area:["Cameron Highlands, Genting Higlands, Bukit Fraser"]},{zone:"PHG07",state:"Pahang",area:["Zon Khas Daerah Rompin, (Mukim Rompin, Mukim Endau, Mukim Pontian)"]},{zone:"PLS01",state:"Perlis",area:["Kangar, Padang Besar, Arau"]},{zone:"PNG01",state:"Pulau Pinang",area:["Seluruh Negeri Pulau Pinang"]},{zone:"PRK01",state:"Perak",area:["Tapah, Slim River, Tanjung Malim"]},{zone:"PRK02",state:"Perak",area:["Kuala Kangsar, Sg. Siput , Ipoh, Batu Gajah, Kampar"]},{zone:"PRK03",state:"Perak",area:["Lenggong, Pengkalan Hulu, Grik"]},{zone:"PRK04",state:"Perak",area:["Temengor, Belum"]},{zone:"PRK05",state:"Perak",area:["Kg Gajah, Teluk Intan, Bagan Datuk, Seri Iskandar, Beruas, Parit, Lumut, Sitiawan, Pulau Pangkor"]},{zone:"PRK06",state:"Perak",area:["Selama, Taiping, Bagan Serai, Parit Buntar"]},{zone:"PRK07",state:"Perak",area:["Bukit Larut"]},{zone:"SBH01",state:"Sabah",area:["Bahagian Sandakan (Timur), Bukit Garam, Semawang, Temanggong, Tambisan, Bandar Sandakan, Sukau"]},{zone:"SBH02",state:"Sabah",area:["Beluran, Telupid, Pinangah, Terusan, Kuamut, Bahagian Sandakan (Barat)"]},{zone:"SBH03",state:"Sabah",area:["Lahad Datu, Silabukan, Kunak, Sahabat, Semporna, Tungku, Bahagian Tawau  (Timur)"]},{zone:"SBH04",state:"Sabah",area:["Bandar Tawau, Balong, Merotai, Kalabakan, Bahagian Tawau (Barat)"]},{zone:"SBH05",state:"Sabah",area:["Kudat, Kota Marudu, Pitas, Pulau Banggi, Bahagian Kudat"]},{zone:"SBH06",state:"Sabah",area:["Gunung Kinabalu"]},{zone:"SBH07",state:"Sabah",area:["Kota Kinabalu, Ranau, Kota Belud, Tuaran, Penampang, Papar, Putatan, Bahagian Pantai Barat"]},{zone:"SBH08",state:"Sabah",area:["Pensiangan, Keningau, Tambunan, Nabawan, Bahagian Pendalaman (Atas)"]},{zone:"SBH09",state:"Sabah",area:["Beaufort, Kuala Penyu, Sipitang, Tenom, Long Pasia, Membakut, Weston, Bahagian Pendalaman (Bawah)"]},{zone:"SGR01",state:"Selangor",area:["Gombak, Petaling, Sepang, Hulu Langat, Hulu Selangor, S.Alam"]},{zone:"SGR02",state:"Selangor",area:["Kuala Selangor, Sabak Bernam"]},{zone:"SGR03",state:"Selangor",area:["Klang, Kuala Langat"]},{zone:"SWK01",state:"Sarawak",area:["Limbang, Lawas, Sundar, Trusan"]},{zone:"SWK02",state:"Sarawak",area:["Miri, Niah, Bekenu, Sibuti, Marudi"]},{zone:"SWK03",state:"Sarawak",area:["Pandan, Belaga, Suai, Tatau, Sebauh, Bintulu"]},{zone:"SWK04",state:"Sarawak",area:["Sibu, Mukah, Dalat, Song, Igan, Oya, Balingian, Kanowit, Kapit"]},{zone:"SWK05",state:"Sarawak",area:["Sarikei, Matu, Julau, Rajang, Daro, Bintangor, Belawai"]},{zone:"SWK06",state:"Sarawak",area:["Lubok Antu, Sri Aman, Roban, Debak, Kabong, Lingga, Engkelili, Betong, Spaoh, Pusa, Saratok"]},{zone:"SWK07",state:"Sarawak",area:["Serian, Simunjan, Samarahan, Sebuyau, Meludam"]},{zone:"SWK08",state:"Sarawak",area:["Kuching, Bau, Lundu, Sematan"]},{zone:"SWK09",state:"Sarawak",area:["Zon Khas (Kampung Patarikan)"]},{zone:"TRG01",state:"Terengganu",area:["Kuala Terengganu, Marang, Kuala Nerus"]},{zone:"TRG02",state:"Terengganu",area:["Besut, Setiu"]},{zone:"TRG03",state:"Terengganu",area:["Hulu Terengganu"]},{zone:"TRG04",state:"Terengganu",area:["Dungun, Kemaman"]},{zone:"WLY01",state:"Wilayah Persekutuan",area:["Kuala Lumpur, Putrajaya"]},{zone:"WLY02",state:"Wilayah Persekutuan",area:["Labuan"]}];
var API='https://www.e-solat.gov.my/index.php?r=esolatApi/takwimsolat';
function getZone(){return localStorage.getItem('pkkimZone')||'SGR01'}
function setZone(z){localStorage.setItem('pkkimZone',z)}
function findZone(code){for(var i=0;i<Z.length;i++){if(Z[i].zone===code)return Z[i]}return Z[0]}
function fmt(s){var a=s.split(':');var h=parseInt(a[0]);return(h>12?h-12:h)+':'+a[1]+(h>=12?' PM':' AM')}
function parseDate(s){var p=s.split('-');var M={Jan:0,Feb:1,Mar:2,Apr:3,May:4,Jun:5,Jul:6,Aug:7,Sep:8,Oct:9,Nov:10,Dec:11};return new Date(p[2],M[p[1]],parseInt(p[0]))}
function fmtDate(d){return d.toLocaleDateString('ms-MY',{weekday:'long',day:'numeric',month:'long',year:'numeric'})}
function render(){
var zone=getZone();var info=findZone(zone);
fetch(API+'&period=today&zone='+zone).then(function(r){return r.json()}).then(function(data){
var t=data.prayerTime[0];var d=fmtDate(parseDate(t.date));
var el=document.getElementById('solatBanner');if(!el)return;
el.innerHTML='<div class="solatBanner-inner"><span class="solatBanner-title">Waktu Solat<br><span id="solatDate" class="solatDate-link">'+d+'</span></span><span>Imsak<br>'+fmt(t.imsak)+'</span><span>Subuh<br>'+fmt(t.fajr)+'</span><span>Syuruk<br>'+fmt(t.syuruk)+'</span><span>Duha<br>'+fmt(t.dhuha)+'</span><span>Zohor<br>'+fmt(t.dhuhr)+'</span><span>Asar<br>'+fmt(t.asr)+'</span><span>Maghrib<br>'+fmt(t.maghrib)+'</span><span>Isyak<br>'+fmt(t.isha)+'</span><span class="solatBanner-location" id="solatZone">&#x1f4cd; '+info.state+': '+info.area.join(', ')+'</span></div>';
document.getElementById('solatZone').addEventListener('click',showZonePicker);
document.getElementById('solatDate').addEventListener('click',showMonthly);
})}
function buildOptions(){
var opts={};
for(var i=0;i<Z.length;i++){
var s=Z[i].state;if(!opts[s])opts[s]={};
opts[s][Z[i].zone]=Z[i].zone+' - '+Z[i].area.join(', ');
}return opts}
function showZonePicker(){
Swal.fire({
title:'Pilih Zon Waktu Solat',
input:'select',
inputOptions:buildOptions(),
inputValue:getZone(),
showCancelButton:true,
cancelButtonText:'Batal',
confirmButtonText:'Pilih',
confirmButtonColor:'#01ab99',
inputValidator:function(v){if(!v)return'Sila pilih zon'}
}).then(function(r){if(r.isConfirmed&&r.value){setZone(r.value);render()}})}
function showMonthly(){
var zone=getZone();var info=findZone(zone);
Swal.fire({title:'Waktu Solat Bulanan',html:'<p>Memuatkan...</p>',width:'90%',showConfirmButton:false,showCloseButton:true,didOpen:function(){
fetch(API+'&period=month&zone='+zone).then(function(r){return r.json()}).then(function(data){
var rows=data.prayerTime;if(!rows||!rows.length){Swal.update({html:'<p>Tiada data</p>'});return}
var today=new Date();today.setHours(0,0,0,0);
var h='<div class="solatTable-wrap"><table class="solatTable"><thead><tr><th>Tarikh</th><th>Imsak</th><th>Subuh</th><th>Syuruk</th><th>Duha</th><th>Zohor</th><th>Asar</th><th>Maghrib</th><th>Isyak</th></tr></thead><tbody>';
for(var i=0;i<rows.length;i++){
var t=rows[i];var rd=parseDate(t.date);var isToday=rd.getTime()===today.getTime();
var rc=isToday?' class="solatToday"':'';
var ds=rd.toLocaleDateString('ms-MY',{day:'numeric',month:'short'});
h+='<tr'+rc+'><td class="solatDate-cell">'+ds+'</td><td>'+fmt(t.imsak)+'</td><td>'+fmt(t.fajr)+'</td><td>'+fmt(t.syuruk)+'</td><td>'+fmt(t.dhuha)+'</td><td>'+fmt(t.dhuhr)+'</td><td>'+fmt(t.asr)+'</td><td>'+fmt(t.maghrib)+'</td><td>'+fmt(t.isha)+'</td></tr>'}
h+='</tbody></table></div>';
var mn=new Date().toLocaleDateString('ms-MY',{month:'long',year:'numeric'});Swal.update({title:'Waktu Solat Bulan '+mn+': '+info.state,html:'<p class="solatModal-subtitle">'+info.area.join(', ')+'</p>'+h});
})}});
}
render()})();
